    }
    ret
}

fn itoa(mut n: isize) -> [u8; 20] {
    let mut buf = [0u8; 20];
    let mut i = 20;
    if n == 0 { buf[19] = b'0'; return buf; }
    while n > 0 && i > 0 {
        i -= 1;
        buf[i] = b'0' + (n % 10) as u8;
        n /= 10;
    }
    buf
}

