#[panic_handler]
fn panic(info: &core::panic::PanicInfo) -> ! {
    let msg = info.message();
    if let Some(location) = info.location() {
        sys_write(2, format_args!("Panicked at {}:{}, {}\n", location.file(), location.line(), msg).to_string().as_bytes());
    } else {
        sys_write(2, format_args!("Panicked: {}\n", msg).to_string().as_bytes());
    }
    sys_exit(-1);
}

